public class MemoryDemo {
    public static void main(String[] args) {
        // Primitive: value stored directly on the stack
        int x = 42;

        // Reference variable 'names' is on the stack
        // The ArrayList object itself lives in the heap
        ArrayList<String> names = new ArrayList<>();

        names.add("Alice");  // "Alice" String object in heap

        // When this method ends, 'x' and 'names' vanish
        // from the stack. The ArrayList and "Alice" stay
        // in the heap until GC reclaims them.
    }
}

// Note: GC reclaims heap objects when no references
// point to them. The 'names' reference disappears when
// main() ends, making the ArrayList eligible for GC.
